  ('social-worker-moex-02401', 'social-worker', 'social-worker-moex-105-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '民國98年修正的「性騷擾防治法」中，下列敘述何者錯誤？', '["該法要求30人以上之機關、部隊、學校、機構或雇用人應訂定性騷擾防治措施", "因教育、訓練等，利用權勢或機會為性騷擾者，得加重科處罰鍰至二分之一", "該法所規定之罪屬於告訴乃論", "該法規範所有場域中陌生人所進行之性騷擾事件處理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:12+00:00", "source_pdf_sha1": "17966fc86054", "answer_pdf_sha1": "da871179884e", "source_family": "moex-gov-tw", "moex": {"exam_code": "105030", "c": "107", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "105", "exam_name": "105年第一次中醫師分階段、營養師心理師護理師社工師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
